// src/builder/DocumentBuilder.ts
import { XMLBuilder } from "fast-xml-parser";

// src/builder/builderOptions.ts
var builderOptions = {
  attributeNamePrefix: "$",
  ignoreAttributes: false,
  format: true
};

// src/helpers/XMLAttributes.ts
function XMLAttributes(attributes) {
  return Object.fromEntries(
    Object.entries(attributes).map(([key, value]) => [
      `${builderOptions.attributeNamePrefix}${key}`,
      value
    ])
  );
}

// src/helpers/getDateString.ts
function getDateString(date2) {
  if (typeof date2 === "string") {
    return date2;
  }
  return `${date2.getFullYear()}-${date2.getMonth() + 1}-${date2.getDate()}`;
}

// src/builder/DocumentBuilder.ts
var DEFAULT_CUSTOMIZATION_ID = "urn:cen.eu:en16931:2017#compliant#urn:fdc:peppol.eu:2017:poacc:billing:3.0";
