      ...this.__buildAmount(
        "TaxExclusiveAmount",
        total.taxExclusiveAmount,
        total.taxExclusiveAmountCurrency ?? currency
      ),
      ...this.__buildAmount(
        "TaxInclusiveAmount",
        total.taxInclusiveAmount,
        total.taxInclusiveAmountCurrency ?? currency
      ),
      ...this.__buildAmount(
        "PayableAmount",
        total.payableAmount,
        total.payableAmountCurrency ?? currency
      ),
